async (params, browser) => {
  // Search Quora
  await browser.open(`https://www.quora.com/search?q=${params.query}`)

  // Wait for results
  await browser.waitForSelector('[class*=\'Question\'], [class*=\'question\'], [class*=\'result\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll for more
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Scroll further
  await browser.scroll({ direction: 'down', amount: 1000 })

  await browser.wait(1500)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('[class*="result"], [class*="Question"], [class*="pagedList"] > div'); for (let i = 0; i < Math.min(items.length, 15); i++) { const el = items[i]; const questionEl = el.querySelector('[class*="question_text"], [class*="Question"] a, a[href*="/"] span[class*="q-text"]'); const answerEl = el.querySelector('[class*="answer"], [class*="snippet"], p'); const authorEl = el.querySelector('[class*="user"], [class*="author"] a'); const upvotesEl = el.querySelector('[class*="upvote"], [class*="vote"]'); const linkEl = el.querySelector('a[href*="/"]'); results.push({ question: questionEl ? questionEl.textContent.trim() : '', answer_preview: answerEl ? answerEl.textContent.trim().substring(0, 300) : '', author: authorEl ? authorEl.textContent.trim() : '', upvotes: upvotesEl ? upvotesEl.textContent.trim() : '', url: linkEl ? linkEl.href : '' }); } return { query: params.query, result_count: results.length, results: results }`)

  return search_results
}
